/* ===================== REDUCER ===================== */
function reducer(state, a){
  switch(a.type){
    case "HYDRATE": return a.payload;
    case "RESET": return JSON.parse(JSON.stringify(seed));
    case "CREATE_OP": {
      const n = 14 + state.ops.length;
      return { ...state, ops:[{ ...a.op, id:`OP-2026-0${n}`, setor:"Corte", recebido:false }, ...state.ops] };
    }
    case "MOVE_OP": return { ...state, ops: state.ops.map(o=>{
      if(o.id!==a.id) return o; const i=SETORES.indexOf(o.setor);
      return { ...o, setor: SETORES[Math.min(Math.max(i+a.dir,0),SETORES.length-1)] };
    })};
    case "RECEBER_OP": return { ...state, ops: state.ops.map(o=> o.id===a.id?{...o,recebido:true}:o) };
    case "ADD_ACERTO": return { ...state, acertos:[{ ...a.acerto, id:"a"+Date.now(), pago:false }, ...state.acertos] };
    case "PAGAR_ACERTO": return { ...state, acertos: state.acertos.map(x=> x.id===a.id?{...x,pago:true}:x) };
    case "PAGAR_COMPRA": return { ...state, compras: state.compras.map(x=> x.id===a.id?{...x,pago:true}:x) };
    case "ADD_COMPRA": {
      let couros=state.couros, comps=state.componentes;
      if(a.alvo?.kind==="couro") couros=couros.map(k=> k.id===a.alvo.id?{...k,m2:k.m2+a.compra.qtd}:k);
      if(a.alvo?.kind==="comp")  comps=comps.map(p=> p.id===a.alvo.id?{...p,qtd:p.qtd+a.compra.qtd}:p);
      return { ...state, couros, componentes:comps, compras:[{ ...a.compra, id:"co"+Date.now(), pago:false }, ...state.compras] };
    }
    case "ADD_MARCA": return { ...state, marcas:[...state.marcas, { ...a.marca, id:"m"+Date.now() }] };
    case "TOGGLE_AUTO": return { ...state, automacoes: state.automacoes.map(x=> x.id===a.id?{...x,on:!x.on}:x) };
    /* ---- CMS ---- */
    case "SITE_HERO": return { ...state, site:{ ...state.site, hero:{ ...state.site.hero, ...a.patch } } };
    case "SITE_CONTATO": return { ...state, site:{ ...state.site, contato:{ ...state.site.contato, ...a.patch } } };
    case "SITE_STAT": return { ...state, site:{ ...state.site, stats: state.site.stats.map((s,i)=> i===a.i?{...s,...a.patch}:s) } };
    case "LINHA_ADD": return { ...state, site:{ ...state.site, linhas:[...state.site.linhas, { id:"l"+Date.now(), titulo:"Nova linha", desc:"Descrição", img:IMG.det }] } };
    case "LINHA_UPD": return { ...state, site:{ ...state.site, linhas: state.site.linhas.map(l=> l.id===a.id?{...l,...a.patch}:l) } };
    case "LINHA_DEL": return { ...state, site:{ ...state.site, linhas: state.site.linhas.filter(l=> l.id!==a.id) } };
    case "GAL_ADD": return { ...state, site:{ ...state.site, galeria:[...state.site.galeria, a.url] } };
    case "GAL_DEL": return { ...state, site:{ ...state.site, galeria: state.site.galeria.filter((_,i)=> i!==a.i) } };
    default: return state;
  }
}

/* ===================== STORAGE ===================== */
const KEY="fermo_plataforma_v1";
async function saveState(s){ try{ if(window.storage) await window.storage.set(KEY, JSON.stringify(s), false); }catch(e){} }
async function loadState(){ try{ if(window.storage){ const r=await window.storage.get(KEY,false); return r? JSON.parse(r.value):null; } }catch(e){} return null; }

