const FONTS = `@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@600;700;800&family=Cormorant+Garamond:ital,wght@0,500;0,600;1,500&family=Inter:wght@400;500;600;700&display=swap');`;

/* ===================== APP ===================== */
export default function App(){
  const [state, dispatch] = useReducer(reducer, seed);
  const [route, setRoute] = useState("site");   // site | login | admin
  const [auth, setAuth] = useState(false);

  useEffect(()=>{ let ok=true; loadState().then(s=>{ if(ok && s) dispatch({type:"HYDRATE",payload:s}); }); return ()=>{ok=false}; }, []);
  useEffect(()=>{ saveState(state); }, [state]);

  return (
    <div style={{fontFamily:"'Inter',system-ui,sans-serif",color:c.ink,background:c.osso,minHeight:"100vh"}}>
      <style>{FONTS+`*{box-sizing:border-box}::-webkit-scrollbar{width:9px;height:9px}::-webkit-scrollbar-thumb{background:${c.line};border-radius:9px}input:focus,select:focus,textarea:focus{outline:2px solid ${c.gold};outline-offset:0}`}</style>
      {route==="site" && <PublicSite site={state.site} onEnter={()=>setRoute(auth?"admin":"login")} />}
      {route==="login" && <Login onBack={()=>setRoute("site")} onOk={()=>{setAuth(true);setRoute("admin");}} />}
      {route==="admin" && auth && <Admin state={state} dispatch={dispatch} onSite={()=>setRoute("site")} onLogout={()=>{setAuth(false);setRoute("site");}} />}
    </div>
  );
}

